rule "Windows - AppLocker - Parsing 31"

when
    to_string($message.SourceName) == "Microsoft-Windows-AppLocker" AND
    (
        to_long($message.event_code) >= 8002 AND
        to_long($message.event_code) <= 8007
    )

then
    let applocker = grok(
        pattern: "%{WORD:appbase}%{GREEDYDATA}%{WORD:appname}[.]%{WORD:appextension} %{GREEDYDATA}[.]",
        value: to_string($message.message),
        only_named_captures: true
    );

    set_fields(applocker);

end

rule "Windows - Applocker - Winlogbeat - Normalization 22"

when
    to_string($message.winlogbeat_event_provider) == "Microsoft-Windows-AppLocker"

then
    rename_field(
        "winlogbeat_winlog_user_domain", 
        "TargetDomainName"
    );
    rename_field(
        "winlogbeat_event_code",
        "event_code"
    );
    rename_field(
        "winlogbeat_winlog_event_id",
        "event_code"
    );
    rename_field(
        "winlogbeat_winlog_user_name", 
        "user_name"
    );
    rename_field(
        "winlogbeat_winlog_user_type", 
        "user_type"
    );
    rename_field(
        "winlogbeat_winlog_user_identifier", 
        "user_id"
    );
    set_field(
        field: "SourceName",
        value: to_string($message.winlogbeat_event_provider)
    );

end

rule "Windows - AppLocker - Parsing 32"

when
    to_string($message.SourceName) == "Microsoft-Windows-AppLocker" AND
    (
        to_long($message.event_code) >= 8002 AND
        to_long($message.event_code) <= 8007
    )

then
    let apppath = regex(
        pattern: "((\\%[A-Z0-9]+\\%)(\\\\[a-zA-Z0-9_.-]+)+\\\\?)",
        value: to_string($message.message)
    );

    let appname = regex(
        pattern:"([__][a-zA-Z0-9_.-]+)+\\\\?",
        value: to_string($message.message)
    );

    set_field("apppath", apppath["0"]);
    set_field("appname", replace(to_string(appname["0"]), to_string(appname["0"]),"PSSCRIPTPOLICYTEST"));

end

rule "Windows - Applocker - NXLog - Normalization 21"

when
    to_string($message.SourceName) == "Microsoft-Windows-AppLocker"

then
    rename_field(
        "Domain", 
        "TargetDomainName"
    );
    rename_field(
        "EventID",
        "event_code"
    );
    rename_field(
        "AccountName", 
        "user_name"
    );
    rename_field(
        "AccountType", 
        "user_type"
    );
    rename_field(
        "UserID", 
        "user_id"
    );

end
